#include <stdio.h>

struct Customer {
    int  account_number;
    char name[30];
    char address[50];
};

int main() {
    struct Customer c[10];
    int i;

    for (i = 0; i < 10; i++) {
        printf("\nCustomer %d:\n", i + 1);
        printf("Account Number: "); scanf("%d", &c[i].account_number);
        printf("Name: ");           scanf("%s", c[i].name);
        printf("Address: ");        scanf("%s", c[i].address);
    }

    printf("\n%-10s %-20s %-30s\n", "Acc.No.", "Name", "Address");
    printf("----------------------------------------------------------\n");
    for (i = 0; i < 10; i++) {
        printf("%-10d %-20s %-30s\n",
               c[i].account_number, c[i].name, c[i].address);
    }
    return 0;
}

#include <stdio.h>
void square(int x) {
    x = x * x;
    printf("Inside: %d\n", x);
}
int main() {
    int a = 5;
    square(a);
    printf("After: %d\n", a); /* Still 5 */
    return 0;
}

#include <stdio.h>
void square(int *x) {
    *x = (*x) * (*x);
    printf("Inside: %d\n", *x);
}
int main() {
    int a = 5;
    square(&a);
    printf("After: %d\n", a); /* Now 25 */
    return 0;
}

#include <stdio.h>

struct Student {
    int  roll;
    char name[30];
    float marks;
};

int main() {
    struct Student s[5];
    int i;

    for (i = 0; i < 5; i++) {
        printf("\nStudent %d:\n", i + 1);
        printf("Roll  : "); scanf("%d", &s[i].roll);
        printf("Name  : "); scanf("%s", s[i].name);
        printf("Marks : "); scanf("%f", &s[i].marks);
    }

    printf("\n%-5s %-20s %-10s\n", "Roll", "Name", "Marks");
    printf("----------------------------------\n");
    for (i = 0; i < 5; i++) {
        printf("%-5d %-20s %-10.2f\n",
               s[i].roll, s[i].name, s[i].marks);
    }
    return 0;
}

#include <stdio.h>

int main() {
    FILE *fp;
    char name[30], address[50];
    char choice;

    fp = fopen("student.dat", "w");
    if (fp == NULL) {
        printf("Error opening file!\n");
        return 1;
    }

    do {
        printf("Name    : "); scanf("%s", name);
        printf("Address : "); scanf("%s", address);
        fprintf(fp, "%s %s\n", name, address);
        printf("Continue? (y/n): ");
        scanf(" %c", &choice);
    } while (choice == 'y' || choice == 'Y');

    fclose(fp);
    printf("Data saved to student.dat\n");
    return 0;
}

#include <stdio.h>

int factorial(int n) {
    if (n == 0 || n == 1)
        return 1;           /* Base case */
    return n * factorial(n - 1);  /* Recursive call */
}

int main() {
    int num;
    printf("Enter a number: ");
    scanf("%d", &num);
    printf("Factorial of %d = %d\n", num, factorial(num));
    return 0;
}
